def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    np.random.seed(2025)
    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    def hypervolume(subset_indices):
        if len(subset_indices) == 0:
            return 0.0
        hv = pg.hypervolume(points[subset_indices])
        return hv.compute(reference_point)

    best_indices = None
    best_hv = -np.inf

    for _ in range(10):
        current = np.random.choice(n, size=k, replace=False)
        current_hv = hypervolume(current)

        improved = True
        while improved:
            improved = False
            np.random.shuffle(current)
            for i in range(k):
                for j in np.random.permutation(n):
                    if j in current:
                        continue
                    candidate = current.copy()
                    candidate[i] = j
                    cand_hv = hypervolume(candidate)
                    if cand_hv > current_hv:
                        current = candidate
                        current_hv = cand_hv
                        improved = True
                        break
                if improved:
                    break

        if current_hv > best_hv:
            best_hv = current_hv
            best_indices = current.copy()

    return points[best_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random

    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    def compute_hv(indices):
        if not indices:
            return 0.0
        return pg.hypervolume(points[list(indices)]).compute(reference_point)

    # Initial greedy selection
    selected = set()
    for _ in range(k):
        best_hv = -np.inf
        best_idx = -1
        for idx in range(n):
            if idx in selected:
                continue
            temp_set = selected | {idx}
            hv = compute_hv(temp_set)
            if hv > best_hv:
                best_hv = hv
                best_idx = idx
        selected.add(best_idx)

    # Fast local improvement with single swaps
    improved = True
    while improved:
        improved = False
        current_hv = compute_hv(selected)

        # Find worst contributor
        worst_idx = -1
        worst_loss = np.inf
        for s in selected:
            temp_set = selected - {s}
            hv_without = compute_hv(temp_set)
            loss = current_hv - hv_without
            if loss < worst_loss:
                worst_loss = loss
                worst_idx = s

        # Try to replace it
        for r in set(range(n)) - selected:
            new_set = (selected - {worst_idx}) | {r}
            new_hv = compute_hv(new_set)
            if new_hv > current_hv:
                selected = new_set
                improved = True
                break

    return points[list(selected)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    def HV_cal(objectives_list: List[np.ndarray]) -> float:
        import pygmo as pg
        if not objectives_list:
            return 0.0
        objectives_array = np.array(objectives_list)
        hv = pg.hypervolume(objectives_array)
        return hv.compute(reference_point)

    def hypervolume_contribution(point: np.ndarray, selected_subset: List[np.ndarray]) -> float:
        if len(selected_subset) == 0:
            return HV_cal([point])
        else:
            hv_before = HV_cal(selected_subset)
            hv_after = HV_cal(selected_subset + [point])
            return hv_after - hv_before

    n, d = points.shape
    selected_indices: List[int] = []
    selected_points: List[np.ndarray] = []

    while len(selected_indices) < k:
        max_contrib = -np.inf
        max_idx = None

        for idx in range(n):
            if idx in selected_indices:
                continue
            point = points[idx]
            contrib = hypervolume_contribution(point, selected_points)
            if contrib > max_contrib:
                max_contrib = contrib
                max_idx = idx

        if max_idx is None:
            remaining_indices = [i for i in range(n) if i not in selected_indices]
            if remaining_indices:
                max_idx = remaining_indices[0]
            else:
                break

        selected_indices.append(max_idx)
        selected_points.append(points[max_idx])

        if len(selected_indices) > 1:
            improved = True
            while improved:
                improved = False
                current_hv = HV_cal(selected_points)
                for i in range(len(selected_indices)):
                    for j in range(n):
                        if j in selected_indices:
                            continue
                        temp_points = selected_points.copy()
                        temp_points[i] = points[j]
                        new_hv = HV_cal(temp_points)
                        if new_hv > current_hv:
                            selected_points = temp_points
                            selected_indices[i] = j
                            current_hv = new_hv
                            improved = True
                            break
                    if improved:
                        break

    subset = np.array(selected_points)
    return subset
